/// CRC-32 with the RFC 7932 Appendix C polynomial, to self-check the decoded dictionary.
fn crc32(data: []const u8) u32 {
    const poly: u32 = 0xedb88320;
    var crc: u32 = 0xffffffff;
    for (data) |byte| {
        var ch: u32 = (crc ^ byte) & 0xff;
        var k: usize = 0;
        while (k < 8) : (k += 1) ch = if (ch & 1 != 0) poly ^ (ch >> 1) else ch >> 1;
        crc = ch ^ (crc >> 8);
    }

    return crc ^ 0xffffffff;
}

pub fn main(process: std.process.Init) !void {
    var arena = std.heap.ArenaAllocator.init(std.heap.page_allocator);
    defer arena.deinit();

    const allocator = arena.allocator();

    var arg_iter = std.process.Args.Iterator.init(process.minimal.args);
    _ = arg_iter.skip();
    const out_path = arg_iter.next() orelse return error.MissingOutputPath;

    // the embedded base64 is a multiline literal, so strip the newlines before decoding.
    const clean = try allocator.alloc(u8, DICT_B64.len);
    var ci: usize = 0;
    for (DICT_B64) |c| {
        switch (c) {
            '\n', '\r', ' ', '\t' => {},
            else => {
                clean[ci] = c;
                ci += 1;
            },
        }
    }

    const decoder = std.base64.standard.Decoder;
    const size = try decoder.calcSizeForSlice(clean[0..ci]);
    const out = try allocator.alloc(u8, size);
    try decoder.decode(out, clean[0..ci]);

    if (out.len != 122784) return error.DictionarySizeMismatch;
    if (crc32(out) != 0x5136cb04) return error.DictionaryCrcMismatch;

    const io = process.io;
    const cwd = std.Io.Dir.cwd();

    const file = try cwd.createFile(io, out_path, .{});
    defer file.close(io);

    var write_buf: [8192]u8 = undefined;
    var writer = file.writer(io, &write_buf);
    try writer.interface.writeAll(out);
    try writer.interface.flush();
}
